function toNum(v, fallback = 0) {
  const n = Number(v);
  return Number.isFinite(n) ? n : fallback;
}

function nowZA() {
  return DateTime.now().setZone('Africa/Johannesburg');
}

function normalizeStatus(value) {
  return String(value || '').trim().toUpperCase();
}

function clean(value) {
  return String(value || '').trim();
}

// --- read source data from earlier nodes ---
const stateRows = $items("B2 — Get STATE").map(i => i.json);
const rulesRows = $items("B3 — Get RULES").map(i => i.json);
const weatherRows = $items("B4 — Get “Weather Now”").map(i => i.json);
const zoneRows = $items("B4B — Get ZONES").map(i => i.json);
const planRows = $items("B5 — Get TODAY DAILY_PLAN").map(i => i.json);

// --- normalize base rows ---
const state = stateRows[0] || {};
const weather = weatherRows[0] || {};

// --- normalize RULES ---
const rules = {};
for (const r of rulesRows) {
  const k = clean(r.rule_key || Object.values(r)[0]);
  const v = r.rule_value ?? Object.values(r)[1];
  if (k) rules[k] = v;
}

// --- map zones by zone_id ---
const zonesById = Object.fromEntries(
  zoneRows
    .filter(z => clean(z.zone_id) !== '')
    .map(z => [clean(z.zone_id), z])
);

// --- keep only relevant plan rows ---
const todayPlan = planRows.filter(r => {
  const s = normalizeStatus(r.status);
  return ['PLANNED', 'RUNNING', 'PAUSED'].includes(s);
});

// --- sort planned rows ---
const sortedPlannedRows = todayPlan
  .filter(r => normalizeStatus(r.status) === 'PLANNED')
  .sort((a, b) => {
    const waterDiff = toNum(b.water_score, 0) - toNum(a.water_score, 0);
    if (waterDiff !== 0) return waterDiff;

    const zoneA = zonesById[clean(a.zone_id)] || {};
    const zoneB = zonesById[clean(b.zone_id)] || {};
    const priorityDiff = toNum(zoneA.priority, 999) - toNum(zoneB.priority, 999);
    if (priorityDiff !== 0) return priorityDiff;

    return clean(a.zone_id).localeCompare(clean(b.zone_id));
  });

const currentZoneId = clean(state.current_zone_id);
const currentStatus = normalizeStatus(state.current_status);

const rainToday = toNum(weather.rain_today_mm || weather.rain_mm, 0);
const windKph = toNum(weather.wind_kph || weather.wind_speed_kph, 0);

// --- thresholds from RULES with safe defaults ---
const liveRainSkipMm = toNum(rules["live_rain_skip_mm"], 2);
const liveWindSkipKph = toNum(rules["wind_pause_kmh"], 35);

const weatherSnapshot = JSON.stringify({
  station_time: weather.timestamp || weather.reading_time || weather.station_time || '',
  weather_summary: weather.weather_summary || weather.summary || '',
  temperature_c: weather.temperature_c || weather.temp_c || '',
  rain_today_mm: rainToday,
  wind_kph: windKph,
  humidity_pct: weather.humidity_pct || weather.humidity || ''
});

// ----------------------------------------------------
// CASE 1: A zone is currently running -> check if stop
// ----------------------------------------------------
if (currentStatus === 'RUNNING' && currentZoneId) {
  const runningRow = todayPlan.find(r =>
    clean(r.zone_id) === currentZoneId &&
    normalizeStatus(r.status) === 'RUNNING'
  );

  if (!runningRow) {
    return [
      {
        json: {
          action: 'DO_NOTHING',
          zone_id: currentZoneId,
          reason: 'STATE says RUNNING but no RUNNING row found in DAILY_PLAN',
          weather_snapshot: weatherSnapshot
        }
      }
    ];
  }

  if (!runningRow.actual_start) {
    return [
      {
        json: {
          action: 'DO_NOTHING',
          plan_id: runningRow.plan_id || '',
          zone_id: currentZoneId,
          reason: 'RUNNING row has no actual_start yet',
          weather_snapshot: weatherSnapshot
        }
      }
    ];
  }

  const startedAt = DateTime.fromISO(String(runningRow.actual_start), { zone: 'utc' });
  if (!startedAt.isValid) {
    return [
      {
        json: {
          action: 'DO_NOTHING',
          plan_id: runningRow.plan_id || '',
          zone_id: currentZoneId,
          reason: 'actual_start is not a valid ISO datetime',
          weather_snapshot: weatherSnapshot
        }
      }
    ];
  }

  const elapsedMinutes = Math.max(
    0,
    Math.floor(nowZA().toUTC().diff(startedAt, 'minutes').minutes)
  );

  const plannedMinutes = toNum(runningRow.planned_minutes, 0);
  const zone = zonesById[currentZoneId] || {};

  if (elapsedMinutes >= plannedMinutes) {
    return [
      {
        json: {
          action: 'STOP_ZONE',
          plan_id: runningRow.plan_id || '',
          zone_id: currentZoneId,
          planned_minutes: plannedMinutes,
          actual_minutes: elapsedMinutes,
          ifttt_off_event: clean(zone.ifttt_off_event),
          ifttt_on_event: clean(zone.ifttt_on_event),
          reason: 'Planned runtime completed',
          weather_snapshot: weatherSnapshot
        }
      }
    ];
  }

  return [
    {
      json: {
        action: 'DO_NOTHING',
        plan_id: runningRow.plan_id || '',
        zone_id: currentZoneId,
        planned_minutes: plannedMinutes,
        actual_minutes: elapsedMinutes,
        reason: `Zone still running (${elapsedMinutes}/${plannedMinutes} min)`,
        weather_snapshot: weatherSnapshot
      }
    }
  ];
}

// ----------------------------------------------------
// CASE 2: Nothing is running -> weather gate first
// ----------------------------------------------------
if (rainToday >= liveRainSkipMm) {
  return [
    {
      json: {
        action: 'DO_NOTHING',
        reason: `Live weather gate blocked start: rain_today_mm ${rainToday} >= ${liveRainSkipMm}`,
        weather_snapshot: weatherSnapshot
      }
    }
  ];
}

if (windKph >= liveWindSkipKph) {
  return [
    {
      json: {
        action: 'DO_NOTHING',
        reason: `Live weather gate blocked start: wind_kph ${windKph} >= ${liveWindSkipKph}`,
        weather_snapshot: weatherSnapshot
      }
    }
  ];
}

// ----------------------------------------------------
// CASE 3: Nothing is running -> start next planned zone
// ----------------------------------------------------
if (sortedPlannedRows.length > 0) {
  const nextRow = sortedPlannedRows[0];
  const zoneId = clean(nextRow.zone_id);
  const zone = zonesById[zoneId] || {};

  return [
    {
      json: {
        action: 'START_ZONE',
        plan_id: nextRow.plan_id || '',
        zone_id: zoneId,
        planned_minutes: toNum(nextRow.planned_minutes, 0),
        ifttt_on_event: clean(zone.ifttt_on_event),
        ifttt_off_event: clean(zone.ifttt_off_event),
        reason: 'Starting next planned zone',
        weather_snapshot: weatherSnapshot
      }
    }
  ];
}

// ----------------------------------------------------
// CASE 4: Nothing left to do
// ----------------------------------------------------
return [
  {
    json: {
      action: 'DO_NOTHING',
      reason: 'No PLANNED rows left for today',
      weather_snapshot: weatherSnapshot
    }
  }
];
